    91→func newWatchableStore(lg *zap.Logger, b backend.Backend, le lease.Lessor, cfg StoreConfig) *watchableStore {
    92→	if lg == nil {
    93→		lg = zap.NewNop()
    94→	}
    95→	s := &watchableStore{
    96→		store:    NewStore(lg, b, le, cfg),
    97→		victimc:  make(chan struct{}, 1),
    98→		unsynced: newWatcherGroup(),
    99→		synced:   newWatcherGroup(),
   100→		stopc:    make(chan struct{}),
   101→	}
   102→	s.store.ReadView = &readView{s}
   103→	s.store.WriteView = &writeView{s}
   104→	if s.le != nil {
   105→		// use this store as the deleter so revokes trigger watch events
   106→		s.le.SetRangeDeleter(func() lease.TxnDelete { return s.Write(traceutil.TODO()) })
   107→	}
   108→	return s
   109→}
