    15→package mvcc
    16→
    17→import (
    18→	"sync"
    19→
    20→	"go.uber.org/zap"
    21→	"k8s.io/utils/third_party/forked/golang/btree"
    22→)
    23→
    24→type index interface {
    25→	Get(key []byte, atRev int64) (rev, created Revision, ver int64, err error)
    26→	Range(key, end []byte, atRev int64) ([][]byte, []Revision)
    27→	Revisions(key, end []byte, atRev int64, limit int) ([]Revision, int)
    28→	CountRevisions(key, end []byte, atRev int64) int
    29→	Put(key []byte, rev Revision)
    30→	Tombstone(key []byte, rev Revision) error
    31→	Compact(rev int64) map[Revision]struct{}
    32→	Keep(rev int64) map[Revision]struct{}
    33→	Equal(b index) bool
    34→
    35→	Insert(ki *keyIndex)
    36→	KeyIndex(ki *keyIndex) *keyIndex
    37→}
    38→
    39→type treeIndex struct {
    40→	sync.RWMutex
    41→	tree *btree.BTree[*keyIndex]
    42→	lg   *zap.Logger
    43→}
    44→
    45→func newTreeIndex(lg *zap.Logger) index {
    46→	return &treeIndex{
    47→		tree: btree.New(32, func(aki *keyIndex, bki *keyIndex) bool {
    48→			return aki.Less(bki)
    49→		}),
    50→		lg: lg,
    51→	}
    52→}
    53→
    54→func (ti *treeIndex) Put(key []byte, rev Revision) {
    55→	keyi := &keyIndex{key: key}
    56→
    57→	ti.Lock()
    58→	defer ti.Unlock()
    59→	okeyi, ok := ti.tree.Get(keyi)
    60→	if !ok {
    61→		keyi.put(ti.lg, rev.Main, rev.Sub)
    62→		ti.tree.ReplaceOrInsert(keyi)
    63→		return
    64→	}
    65→	okeyi.put(ti.lg, rev.Main, rev.Sub)
    66→}
    67→
    68→func (ti *treeIndex) Get(key []byte, atRev int64) (modified, created Revision, ver int64, err error) {
    69→	ti.RLock()
    70→	defer ti.RUnlock()
    71→	return ti.unsafeGet(key, atRev)
    72→}
    73→
    74→func (ti *treeIndex) unsafeGet(key []byte, atRev int64) (modified, created Revision, ver int64, err error) {
    75→	keyi := &keyIndex{key: key}
    76→	if keyi = ti.keyIndex(keyi); keyi == nil {
    77→		return Revision{}, Revision{}, 0, ErrRevisionNotFound
    78→	}
    79→	return keyi.get(ti.lg, atRev)
    80→}
    81→
    82→func (ti *treeIndex) KeyIndex(keyi *keyIndex) *keyIndex {
    83→	ti.RLock()
    84→	defer ti.RUnlock()
    85→	return ti.keyIndex(keyi)
    86→}
    87→
    88→func (ti *treeIndex) keyIndex(keyi *keyIndex) *keyIndex {
    89→	if ki, ok := ti.tree.Get(keyi); ok {
    90→		return ki
    91→	}
    92→	return nil
    93→}
    94→
    95→func (ti *treeIndex) unsafeVisit(key, end []byte, f func(ki *keyIndex) bool) {
    96→	keyi, endi := &keyIndex{key: key}, &keyIndex{key: end}
    97→
    98→	ti.tree.AscendGreaterOrEqual(keyi, func(item *keyIndex) bool {
    99→		if len(endi.key) > 0 && !item.Less(endi) {
   100→			return false
   101→		}
   102→		if !f(item) {
   103→			return false
   104→		}
   105→		return true
   106→	})
   107→}
   108→
   109→// Revisions returns limited number of revisions from key(included) to end(excluded)
   110→// at the given rev. The returned slice is sorted in the order of key. There is no limit if limit <= 0.
   111→// The second return parameter isn't capped by the limit and reflects the total number of revisions.
   112→func (ti *treeIndex) Revisions(key, end []byte, atRev int64, limit int) (revs []Revision, total int) {
   113→	ti.RLock()
   114→	defer ti.RUnlock()
   115→
   116→	if end == nil {
   117→		rev, _, _, err := ti.unsafeGet(key, atRev)
   118→		if err != nil {
   119→			return nil, 0
   120→		}
   121→		return []Revision{rev}, 1
   122→	}
   123→	ti.unsafeVisit(key, end, func(ki *keyIndex) bool {
   124→		if rev, _, _, err := ki.get(ti.lg, atRev); err == nil {
   125→			if limit <= 0 || len(revs) < limit {
   126→				revs = append(revs, rev)
   127→			}
   128→			total++
   129→		}
   130→		return true
   131→	})
   132→	return revs, total
   133→}
   134→
   135→// CountRevisions returns the number of revisions
   136→// from key(included) to end(excluded) at the given rev.
   137→func (ti *treeIndex) CountRevisions(key, end []byte, atRev int64) int {
   138→	ti.RLock()
   139→	defer ti.RUnlock()
   140→
   141→	if end == nil {
   142→		_, _, _, err := ti.unsafeGet(key, atRev)
   143→		if err != nil {
   144→			return 0
   145→		}
   146→		return 1
   147→	}
   148→	total := 0
   149→	ti.unsafeVisit(key, end, func(ki *keyIndex) bool {
   150→		if _, _, _, err := ki.get(ti.lg, atRev); err == nil {
   151→			total++
   152→		}
   153→		return true
   154→	})
   155→	return total
   156→}
   157→
   158→func (ti *treeIndex) Range(key, end []byte, atRev int64) (keys [][]byte, revs []Revision) {
   159→	ti.RLock()
   160→	defer ti.RUnlock()
   161→
   162→	if end == nil {
   163→		rev, _, _, err := ti.unsafeGet(key, atRev)
   164→		if err != nil {
   165→			return nil, nil
   166→		}
   167→		return [][]byte{key}, []Revision{rev}
   168→	}
   169→	ti.unsafeVisit(key, end, func(ki *keyIndex) bool {
   170→		if rev, _, _, err := ki.get(ti.lg, atRev); err == nil {
   171→			revs = append(revs, rev)
   172→			keys = append(keys, ki.key)
   173→		}
   174→		return true
   175→	})
   176→	return keys, revs
   177→}
   178→
   179→func (ti *treeIndex) Tombstone(key []byte, rev Revision) error {
   180→	keyi := &keyIndex{key: key}
   181→
   182→	ti.Lock()
   183→	defer ti.Unlock()
   184→	ki, ok := ti.tree.Get(keyi)
   185→	if !ok {
   186→		return ErrRevisionNotFound
   187→	}
   188→
   189→	return ki.tombstone(ti.lg, rev.Main, rev.Sub)
   190→}
   191→
   192→func (ti *treeIndex) Compact(rev int64) map[Revision]struct{} {
   193→	available := make(map[Revision]struct{})
   194→	ti.lg.Info("compact tree index", zap.Int64("revision", rev))
   195→	ti.Lock()
   196→	clone := ti.tree.Clone()
   197→	ti.Unlock()
   198→
   199→	clone.Ascend(func(keyi *keyIndex) bool {
   200→		// Lock is needed here to prevent modification to the keyIndex while
   201→		// compaction is going on or revision added to empty before deletion
   202→		ti.Lock()
   203→		keyi.compact(ti.lg, rev, available)
   204→		if keyi.isEmpty() {
   205→			_, ok := ti.tree.Delete(keyi)
   206→			if !ok {
   207→				ti.lg.Panic("failed to delete during compaction")
   208→			}
   209→		}
   210→		ti.Unlock()
   211→		return true
   212→	})
   213→	return available
   214→}
   215→
   216→// Keep finds all revisions to be kept for a Compaction at the given rev.
   217→func (ti *treeIndex) Keep(rev int64) map[Revision]struct{} {
   218→	available := make(map[Revision]struct{})
   219→	ti.RLock()
   220→	defer ti.RUnlock()
   221→	ti.tree.Ascend(func(keyi *keyIndex) bool {
   222→		keyi.keep(rev, available)
   223→		return true
   224→	})
   225→	return available
   226→}
   227→
   228→func (ti *treeIndex) Equal(bi index) bool {
   229→	b := bi.(*treeIndex)
   230→
   231→	if ti.tree.Len() != b.tree.Len() {
   232→		return false
   233→	}
   234→
   235→	equal := true
   236→
   237→	ti.tree.Ascend(func(aki *keyIndex) bool {
   238→		bki, _ := b.tree.Get(aki)
   239→		if !aki.equal(bki) {
   240→			equal = false
   241→			return false
   242→		}
   243→		return true
   244→	})
   245→
   246→	return equal
   247→}
   248→
   249→func (ti *treeIndex) Insert(ki *keyIndex) {
   250→	ti.Lock()
   251→	defer ti.Unlock()
   252→	ti.tree.ReplaceOrInsert(ki)
   253→}
